/* 
  Solution to "LCM Partition" by grouped 0/1 knapsack over prime‐powers.
  We maximize sum of logs of chosen prime‐powers (equivalently maximizing LCM),
  then fill leftover with 1's for exact sum N, yielding lexicographically minimal.
*/
#include <bits/stdc++.h>
using namespace std;

static const double NEG_INF = -1e300;
static const double EPS = 1e-9;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    // 1) Sieve primes up to N
    vector<bool> is_composite(N+1, false);
    vector<int> primes;
    for(int i = 2; i <= N; i++){
        if(!is_composite[i]){
            primes.push_back(i);
            if((long long)i * i <= N)
                for(int j = i*i; j <= N; j += i)
                    is_composite[j] = true;
        }
    }

    // 2) For each prime, precompute its powers ≤ N
    //    and their log-values.
    int P = primes.size();
    vector<vector<pair<int,double>>> options(P);
    for(int idx = 0; idx < P; idx++){
        int p = primes[idx];
        long long w = p;
        while(w <= N){
            options[idx].push_back({int(w), log((double)w)});
            w *= p;
        }
    }

    // 3) DP array: dp[c] = best state for total cost c
    struct State {
        double val;          // sum of logs = log(LCM)
        vector<int> sel;     // chosen prime-powers (strictly increasing)
    };

    vector<State> dp(N+1);
    // init
    for(int c = 1; c <= N; c++){
        dp[c].val = NEG_INF;
    }
    dp[0].val = 0.0;  // no prime-powers, LCM=1 => log=0

    // 4) Grouped knapsack over primes
    for(int idx = 0; idx < P; idx++){
        auto nxt = dp;  // copy current dp to nxt
        for(int c = 0; c <= N; c++){
            if(dp[c].val <= NEG_INF/2) continue;
            // try pick one power of prime primes[idx]
            for(auto &opt: options[idx]){
                int w = opt.first;
                double lg = opt.second;
                int nc = c + w;
                if(nc > N) break;
                double nv = dp[c].val + lg;
                auto &st = nxt[nc];
                bool better = false;
                if(nv > st.val + EPS){
                    better = true;
                } else if (fabs(nv - st.val) <= EPS) {
                    // tie on LCM; prefer lex-smaller -> but first we want
                    // more leftover= smaller nc  => more leading 1's
                    // since we store by exact cost nc, we'll resolve after full DP.
                    // Here we only compare the sel vectors for the same nc.
                    vector<int> cand = dp[c].sel;
                    cand.push_back(w);
                    if(cand < st.sel) better = true;
                }
                if(better){
                    // accept new state
                    st.val = nv;
                    st.sel = dp[c].sel;
                    st.sel.push_back(w);
                }
            }
        }
        dp.swap(nxt);
    }

    // 5) Extract best among dp[0..N]:
    //    maximize (val, leftover = N-c), tie-break val, leftover
    //    if STILL tie, tie-break sel lex.
    double bestVal = NEG_INF;
    int bestCost = 0;
    vector<int> bestSel;
    for(int c = 0; c <= N; c++){
        if(dp[c].val <= NEG_INF/2) continue;
        double v = dp[c].val;
        int leftover = N - c;
        bool take = false;
        if(v > bestVal + EPS){
            take = true;
        } else if(fabs(v - bestVal) <= EPS){
            // more leftover => more leading 1's => lex-smaller
            if(leftover > (N - bestCost)) {
                take = true;
            } else if(leftover == (N - bestCost)){
                if(dp[c].sel < bestSel) take = true;
            }
        }
        if(take){
            bestVal = v;
            bestCost = c;
            bestSel = dp[c].sel;
        }
    }

    // 6) Output: first (N - bestCost) ones, then bestSel in ascending order
    bool first = true;
    for(int i = 0; i < N - bestCost; i++){
        if(!first) cout << ' ';
        cout << 1;
        first = false;
    }
    for(int x: bestSel){
        if(!first) cout << ' ';
        cout << x;
        first = false;
    }
    if(first){
        // N==0? not possible since N>=1. But guard anyway.
        cout << 1;
    }
    cout << "\n";
    return 0;
}

