// Text encoder
void encode_text(const string &s) {
    vector<vector<ll>> sentences;
    vector<ll> wordVals;
    int n = s.size();
    ll curWord = 0; bool inWord = false;
    vector<ll> curSentence;
    int wordPos = 0;
    for(int i = 0; i <= n; i++) {
        char c = (i<n? s[i] : '.'); // sentinel to flush last
        if (isalpha(c)) {
            inWord = true;
            curWord += (int)c;
        } else {
            if (inWord) {
                // end of word
                curSentence.push_back(curWord);
                curWord = 0;
                inWord = false;
            }
            if (c == ','
             || c == ' ') {
                // skip
            } else if (c == '.') {
                // end of sentence
                if (!curSentence.empty()) {
                    sentences.push_back(curSentence);
                    curSentence.clear();
                }
            }
        }
    }
    // For each sentence, add position, sum, build 32‐dim
    for(auto &sent : sentences) {
        ll sVal = 0; 
        for(int i = 0; i < (int)sent.size(); i++) {
            sent[i] += (i+1);
            sVal += sent[i];
        }
        // 32 dims
        for(int i = 1; i <= 32; i++) {
            ll v = (sVal * i) % 1557;
            cout << v << (i<32? ' ' : '\n');
        }
    }
}

