   then adjust minor over-count by dropping smallest diffs.
*/
#include <bits/stdc++.h>
using namespace std;
using ll = long long;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, s, t;
    cin >> n >> s >> t;
    vector<int> a(n), b(n);
    for(int i = 0; i < n; i++) cin >> a[i];
    for(int i = 0; i < n; i++) cin >> b[i];
    int k = s + t;
    // Quick exit: pick only t best b[i] if s==0
    // or only s best a[i] if t==0 (but our general code handles s==0 or t==0).

    auto eval = [&](int lam){
        // Returns how many A-picks among top k with penalty lam
        static vector<pair<int,int>> V;
        V.clear();
        V.reserve(n);
        for(int i = 0; i < n; i++){
            int diff = (a[i] - b[i]) + lam;    // gainA - gainB
            int best_gain = b[i] + max(diff, 0);
            V.emplace_back(best_gain, diff);
        }
        // [FIX] 将 generic lambda 改为显式类型，兼容 C++11
        nth_element(V.begin(), V.begin() + k, V.end(),
            [](const pair<int,int>& L, const pair<int,int>& R){
                return L.first > R.first;
            });
        int cntA = 0;
        for(int i = 0; i < k; i++){
            if (V[i].second > 0) cntA++;
        }
        return cntA;
    };

    // Binary search smallest lam so that eval(lam) >= s
    int lo = -5000, hi = 5000;
    while(lo < hi){
        int mid = (lo + hi) >> 1;
        if (eval(mid) >= s) hi = mid;
        else lo = mid + 1;
    }
    int lam = lo;

    // Final selection at lam, but also accumulate gains & diffs
    vector<pair<int,int>> V; // (best_gain, diff)
    V.reserve(n);
    for(int i = 0; i < n; i++){
        int diff = (a[i] - b[i]) + lam;
        int best_gain = b[i] + max(diff, 0);
        V.emplace_back(best_gain, diff);
    }
    // [FIX] 同上，将 comparator 改为显式类型
    sort(V.begin(), V.end(),
         [](const pair<int,int>& L, const pair<int,int>& R){
             return L.first > R.first;
         });

    // Sum the top k best_gain, collect diffs>0
    ll sum_gain = 0;
    vector<int> posDiff;
    posDiff.reserve(k);
    for(int i = 0; i < k; i++){
        sum_gain += V[i].first;
        if (V[i].second > 0)
            posDiff.push_back(V[i].second);
    }

    int cntA = (int)posDiff.size();
    int extra = cntA - s; // how many too many A-picks
    ll sum_remove = 0;
    if (extra > 0) {
        sort(posDiff.begin(), posDiff.end());
        for(int i = 0; i < extra; i++)
            sum_remove += posDiff[i];
    }

    // Remove the λ-bias from exactly s A-picks
    ll answer = sum_gain - sum_remove - ll(lam) * ll(s);
    cout << answer << "\n";
    return 0;
}

