        nth_element(V.begin(), V.begin() + k, V.end(),
            [](const pair<int,int>& L, const pair<int,int>& R){
                if(L.first != R.first) return L.first > R.first;
                return L.second > R.second;
            });
        int cntA = 0;
        for(int i = 0; i < k; i++){
            if (V[i].second > 0) cntA++;
        }
        return cntA;
