        else lo = mid + 1;
    }
    int lam = lo;

    // 最终在 lam 下选前 k 个，并累计得分 & diff
    vector<pair<int,int>> V;
    V.reserve(n);
    for(int i = 0; i < n; i++){
        int diff = (a[i] - b[i]) + lam;
        int best_gain = b[i] + max(diff, 0);
        V.emplace_back(best_gain, diff);
