             if(L.first != R.first) return L.first > R.first;
             return L.second > R.second;
         });

    ll sum_gain = 0;
    vector<int> posDiff;
    posDiff.reserve(k);
    for(int i = 0; i < k; i++){
        sum_gain += V[i].first;
        if (V[i].second > 0)
            posDiff.push_back(V[i].second);
    }

    int cntA = (int)posDiff.size();
    int extra = cntA - s; // 多余的 A 侧数
    ll sum_remove = 0;
